// Default fallback for any unmatched product_type / campaign_type combination
const defaultCampaign = {
  campaign_name: 'Crystallux AI Sales Engine',
  campaign_value_proposition: 'Automate your entire sales process with AI',
  campaign_pain_point: 'Manual sales processes limiting growth potential',
  campaign_call_to_action: 'Book a 15-minute demo to see Crystallux in action',
  campaign_tone: 'Professional and curious'
};

// ─────────────────────────────────────────────
// ROUTING LOGIC
// ─────────────────────────────────────────────
let config = defaultCampaign;

if (campaigns[productType]) {
  if (campaigns[productType][campaignType]) {
    // Exact match on both product_type and campaign_type
    config = campaigns[productType][campaignType];
  } else {
    // Product type matched but campaign type did not — use first available
    const firstKey = Object.keys(campaigns[productType])[0];
    config = campaigns[productType][firstKey];
  }
}

const now = new Date().toISOString();

return {
  json: {
    // Preserve all original lead fields
    ...lead,
    // Campaign assignment
    campaign_name: config.campaign_name,
    campaign_type: lead.recommended_campaign_type || 'general_outreach',
    campaign_value_proposition: config.campaign_value_proposition,
    campaign_pain_point: config.campaign_pain_point,
    campaign_call_to_action: config.campaign_call_to_action,
    campaign_tone: config.campaign_tone,
    // Status update
    lead_status: 'Campaign Assigned',
    updated_at: now
  }
};

